-- non-superuser role; migrations/seeders run as the owner and bypass.

-- Migration: company row-level-security fence for selling.quotations
-- Generated by metaphor-schema (ADR-0008). company_id is scoped per request
-- via `set_config('app.company_id', <uuid>, true)`; an unset var sees zero rows.

ALTER TABLE selling.quotations ENABLE ROW LEVEL SECURITY;
ALTER TABLE selling.quotations FORCE  ROW LEVEL SECURITY;
DROP POLICY IF EXISTS quotations_company_isolation ON selling.quotations;
CREATE POLICY quotations_company_isolation ON selling.quotations
    FOR ALL
    USING      (company_id = NULLIF(current_setting('app.company_id', true), '')::uuid)
    WITH CHECK (company_id = NULLIF(current_setting('app.company_id', true), '')::uuid);

